#include <bits/stdc++.h>
using namespace std;
#define int unsigned long long
int t,k,n,m;
int ksm(int b) {
	int ans=1;
	for(int i=1; i<=b; i++) {
		ans=ans*i;
	}
	return ans;
}
int C(int n,int m) {
	return ksm(n)/(ksm(m)*ksm(n-m));
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>t>>k;
	while(t--) {
		cin>>n>>m;
		int ans=0;
		for(int i=0; i<=n; i++) {
			for(int j=0; j<=min(m,i); j++) {
				if(C(i,j)%k==0) {
					ans++;
				}
			}
		}
		cout<<ans<<"\n";
	}
	return 0;
}
